SELECT r.*, u.username AS username, c.court_name AS courtName, c.location AS courtLocation
FROM reservations r
LEFT JOIN users u ON r.user_id = u.id
LEFT JOIN courts c ON r.court_id = c.id
WHERE r.court_id = #{courtId}
  AND r.reserve_date = #{reserveDate}
  AND r.status != 'cancelled'
  AND r.start_time < #{endTime}
  AND r.end_time > #{startTime}

SELECT r.*, u.username AS username, c.court_name AS courtName, c.location AS courtLocation
FROM reservations r
LEFT JOIN users u ON r.user_id = u.id
LEFT JOIN courts c ON r.court_id = c.id
WHERE r.court_id = #{courtId}
  AND r.reserve_date = #{reserveDate}
  AND r.status != 'cancelled'
  AND r.start_time < #{endTime}
  AND r.end_time > #{startTime}
FOR UPDATE

mapper.update:
UPDATE reservations
SET status = #{status}
WHERE id = #{id}

UPDATE reservations
SET status = 'completed', update_time = NOW()
WHERE id = #{id}
